import{readdirSync,statSync}from"node:fs";import{readFile}from"node:fs/promises";import{parse as parseYAMLContents}from"yaml";import{parse as parseTOML}from"smol-toml";import stripJsonComments from"strip-json-comments";import{LoaderError}from"./errors.js";import{extname,join}from"./path.js";export const isDirectory=(r,t)=>{try{return statSync(t?join(r,t):r).isDirectory()}catch{return!1}};export const isFile=(r,t)=>{try{return statSync(t?join(r,t):r).isFile()}catch{return!1}};export const findFile=(r,t)=>{const o=join(r,t);return isFile(o)?o:void 0};export const loadFile=async r=>{try{return(await readFile(r)).toString()}catch(t){throw new LoaderError(`Error loading ${r}`,{cause:t})}};export const hasFileWithExtension=(r,t,o)=>{if(!isDirectory(r,t))return!1;try{for(const e of readdirSync(join(r,t)))if(o.includes(extname(e)))return!0}catch{}return!1};export const loadJSON=async r=>{const t=await loadFile(r);try{return JSON.parse(t)}catch{return parseJSONC(r,t)}};export const loadJSONC=async r=>{const t=await loadFile(r);return parseJSONC(r,t)};export const loadYAML=async r=>{const t=await loadFile(r);return parseYAML(t)};export const loadTOML=async r=>{const t=await loadFile(r);return parseTOML(t)};export const parseJSONC=async(r,t)=>{try{return JSON.parse(stripJsonComments(t,{trailingCommas:!0,whitespace:!1}))}catch(t){const o=`Error parsing ${r} ${".json5"===extname(r)?"JSON5 features beyond comments and trailing commas are not fully supported. Consider converting to .jsonc format.":""}`;throw new LoaderError(o,{cause:t})}};export const parseYAML=r=>parseYAMLContents(r,{logLevel:"error"});